$toolDefinition_web_form_submitter = array (
  'type' => 'function',
  'function' => 
  array (
    'name' => 'web_form_submitter',
    'description' => 'Fetch a URL, parse all HTML forms using DOMDocument/DOMXPath, automatically detect CSRF tokens and hidden fields, fill in user-specified field values, and submit the form via HTTP POST or GET. Handles input, textarea, select, checkbox, radio, and hidden fields. Resolves relative action URLs. Returns the submission response with status code, headers, and body. First web automation/bot capability in the ecosystem — programmatically interact with web forms. Never throws — all errors returned as structured data.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
      array (
        'url' => 
        array (
          'type' => 'string',
          'description' => 'The URL of the page containing the form to fill and submit.',
        ),
        'form_index' => 
        array (
          'type' => 'integer',
          'description' => 'Which form on the page to use (0-indexed, default: 0).',
        ),
        'fields' => 
        array (
          'type' => 'object',
          'description' => 'Associative object mapping field names to values to fill in. E.g. {"username": "test", "password": "secret"}. Hidden fields and CSRF tokens are auto-detected and included.',
        ),
        'submit_button' => 
        array (
          'type' => 'string',
          'description' => 'Name of the submit button to \'click\' (default: auto-detect the first submit button).',
        ),
